import axios from "axios";

const fallbackBackendUrl =
  typeof window !== "undefined"
    ? `${window.location.protocol}//${window.location.hostname}:8001`
    : "http://localhost:8001";

const configuredBackendUrl = (process.env.REACT_APP_BACKEND_URL || fallbackBackendUrl)
  .trim()
  .replace(/\/+$/, "");

export const API_BASE_URL = `${configuredBackendUrl}/api`;

export const api = axios.create({
  baseURL: API_BASE_URL,
  timeout: 120000,
});

export const getApiErrorMessage = (error, fallbackMessage) => {
  const responseDetail = error?.response?.data?.detail;

  if (Array.isArray(responseDetail) && responseDetail.length > 0) {
    return responseDetail.map((item) => item?.msg || String(item)).join(". ");
  }

  if (typeof responseDetail === "string" && responseDetail.trim()) {
    return responseDetail;
  }

  if (error?.message) {
    return `${fallbackMessage}: ${error.message}`;
  }

  return fallbackMessage;
};
